import React from 'react';
import './App.css';

function App() {
  const [count, setCount] = React.useState(0);

  const onClickMinus = () => {
    if(count !== 0) {
      setCount(count - 1);
    }
  };

  const onClickPlus = () => {
    setCount(count + 1);
  };

  const [open, setOpen] = React.useState(false);


  const questions = [
    {
      title: 'React - это ... ?',
      variants: ['библиотека', 'фреймворк', 'приложение'],
      correct: 0,
    },
    {
      title: 'Компонент - это ... ',
      variants: ['приложение', 'часть приложения', ''],
      correct: 1,
    },
    {
      title: 'Что такое JSX?',
      variants: ['Это просто HTML', 'Это функция', 'Этот же '],
      correct: 2,
    },
  ]

  return (
    <div className="App">
       <div className="counter">
             <h2 className="title">Счётчик:</h2>
             <h1 className="output">{count}</h1>
             <div className="block_buttons">
                <button onClick={onClickMinus} className="Counter_button minus">- Minus</button>
                <button onClick={onClickPlus} className="Counter_button plus">Plus +</button>
             </div>
       </div>

       <hr/>

       <div className="modalWindow">
                <button onClick={() => setOpen(true)} className="img_button open-modal-btn">
                     🔐 Открыть окно
                </button>
                <button onClick={() => setOpen(false)} className="img_button close-modal-btn">
                     🔐 Закрыть окно
                </button>
        <div className={`overlay animated ${open ? 'show' : ''}`}>
            <div className='modal'>
                    <img className="img-1" src='http://www.rosphoto.com/images/u/articles/1510/3_13.jpg' alt="Uchiha"/>
            </div>
         </div>
       </div>

       <div className="third_App">
           <div className=''>
              <h1>Что такое UseState?</h1>
              <ul>
                  <li>Это функция для хранения данных компонента</li>
                  <li>Это глобальный стейт</li>
                  <li>Это когда ты никому не нужен</li>
              </ul>
           </div>
       </div>
    </div>
  );
}

export default App;
